function candidate(identifier, handler) {
  const container = document.getElementById(identifier);
  if (!container) {
    throw new Error("Element not found");
  }

  const textBox = container.querySelector('input[type="text"], input:not([type])');
  if (!textBox) {
    throw new Error("Input not found");
  }

  const sendValue = () => handler(textBox.value);

  textBox.addEventListener("input", event => {
    event.preventDefault();
    sendValue();
  });

  sendValue();
}
